"""
ARCHANGEL FORGE v3 — Umbrella Dynamics agent factory + client usage & billing system
=====================================================================================
Everything v2 did (bilingual intake, EN/ES/bilingual agents, locked voice, logo),
plus a full per-client operations layer:

  TAGGING      every agent gets a unique client_code at creation, stored in the DB
  USAGE        /tasks/sync pulls each agent's conversations from ElevenLabs
               (duration + credits when available) and attributes them per client
  BILLING      plans with base fee / included minutes / overage rate; monthly
               statements calculated automatically per client
  THRESHOLDS   alert at 80% of included minutes, action proposed at 100%;
               spike detection (last 24h vs. trailing 14-day average);
               account-level credit monitoring vs. your ElevenLabs plan
  ALERTS       stored in the dashboard + optional push to your phone via any
               webhook (ntfy.sh works great: set ALERT_WEBHOOK_URL)
  AUDIT        every create / modify / suspend / approval is logged per client
  APPROVAL     consequential actions (suspending an over-limit client) are
               queued for your approve/dismiss by default; flip AUTO_EXECUTE=auto
               later to make them automatic
  EXPORT       per-client JSON export (config + usage + audit) for clean
               migration; full-database backup/restore endpoints

Environment variables (Render -> Environment):
  OPENROUTER_API_KEY    required
  ELEVENLABS_API_KEY    required
  INTAKE_PASSWORD       required (intake form)
  ADMIN_PASSWORD        optional (defaults to INTAKE_PASSWORD) - dashboard/API
  ELEVEN_VOICE_ID       optional - locked default voice for all agents
  OPENROUTER_MODEL      optional (default anthropic/claude-sonnet-4.5)
  TRIAL_DAYS            optional (default 7)
  ALERT_WEBHOOK_URL     optional - e.g. https://ntfy.sh/your-secret-topic
  AUTO_EXECUTE          optional - "manual" (default) or "auto"
  DB_FILE               optional (default forge.db)

Because Render's free-tier disk resets on redeploy:
  - usage data is a CACHE: one /tasks/sync rebuilds all history from ElevenLabs
  - the client registry is what matters: download /backup regularly and
    restore with /restore after a redeploy if needed
"""

import os
import json
import time
import sqlite3
import secrets
import datetime
import requests
from flask import Flask, request, render_template_string, Response, redirect

app = Flask(__name__)

# ---------------- configuration ----------------
OPENROUTER_API_KEY = os.environ.get("OPENROUTER_API_KEY", "")
ELEVENLABS_API_KEY = os.environ.get("ELEVENLABS_API_KEY", "")
INTAKE_PASSWORD = os.environ.get("INTAKE_PASSWORD", "")
ADMIN_PASSWORD = os.environ.get("ADMIN_PASSWORD", INTAKE_PASSWORD)
OPENROUTER_MODEL = os.environ.get("OPENROUTER_MODEL", "anthropic/claude-sonnet-4.5")
TRIAL_DAYS = int(os.environ.get("TRIAL_DAYS", "7"))
DEFAULT_VOICE_ID = os.environ.get("ELEVEN_VOICE_ID", "").strip()
ALERT_WEBHOOK_URL = os.environ.get("ALERT_WEBHOOK_URL", "").strip()
AUTO_EXECUTE = os.environ.get("AUTO_EXECUTE", "manual").lower()  # manual | auto
DB_FILE = os.environ.get("DB_FILE", "forge.db")
LEGACY_CLIENTS_FILE = "clients.json"

ALERT_PCT = 0.80          # alert when a client passes 80% of included minutes
SPIKE_MULTIPLIER = 3.0    # last-24h minutes > 3x trailing daily average = spike
SPIKE_MIN_MINUTES = 10    # ignore spikes below this floor
ACCOUNT_ALERT_PCT = 0.80  # alert when ElevenLabs credits pass 80% of plan
# --- affiliate commissions (adjustable via Render env vars) ---
AFF_COMMISSION_PCT = float(os.environ.get("AFF_COMMISSION_PCT", "20"))   # % of monthly base
AFF_WINDOW_MONTHS = int(os.environ.get("AFF_WINDOW_MONTHS", "12"))       # months per referral

LOGO_B64 = ""
LOGO_IMG = ('<img src="data:image/png;base64,' + LOGO_B64 +
            '" alt="Umbrella Dynamics" style="width:84px;height:84px;display:block;margin:0 auto 10px">')

ELEVEN = "https://api.elevenlabs.io"


# =========================================================================
# database
# =========================================================================
def db():
    conn = sqlite3.connect(DB_FILE)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    conn = db()
    conn.executescript("""
    CREATE TABLE IF NOT EXISTS plans(
      id TEXT PRIMARY KEY, name TEXT, monthly_base REAL,
      included_minutes REAL, overage_per_min REAL);
    CREATE TABLE IF NOT EXISTS clients(
      client_code TEXT PRIMARY KEY, business_name TEXT, owner_name TEXT,
      agent_id TEXT, language TEXT, voice_id TEXT, plan_id TEXT DEFAULT 'solo',
      status TEXT DEFAULT 'trial', ref_code TEXT,
      trial_start TEXT, trial_end TEXT, created_at TEXT,
      config_json TEXT);
    CREATE TABLE IF NOT EXISTS usage(
      conversation_id TEXT PRIMARY KEY, client_code TEXT, agent_id TEXT,
      start_unix INTEGER, duration_secs REAL, credits REAL, synced_at TEXT);
    CREATE TABLE IF NOT EXISTS events(
      id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT, client_code TEXT,
      kind TEXT, detail TEXT);
    CREATE TABLE IF NOT EXISTS alerts(
      id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT, client_code TEXT,
      level TEXT, message TEXT, acked INTEGER DEFAULT 0, dedupe_key TEXT);
    CREATE TABLE IF NOT EXISTS pending_actions(
      id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT, client_code TEXT,
      action TEXT, reason TEXT, status TEXT DEFAULT 'pending', decided_at TEXT);
    CREATE TABLE IF NOT EXISTS meta(key TEXT PRIMARY KEY, value TEXT);
    """)
    # canonical plans — upserted on every boot so pricing stays in sync with the site
    for p in (("trial", "Trial", 0, 60, 0),
              ("starter", "Starter", 99, 300, 0.20),
              ("growth", "Growth", 149, 600, 0.18),
              ("premium", "Premium", 249, 1200, 0.15)):
        conn.execute("INSERT OR REPLACE INTO plans VALUES(?,?,?,?,?)", p)
    conn.commit()

    # one-time migration from the old clients.json if present
    if os.path.exists(LEGACY_CLIENTS_FILE) and \
       not conn.execute("SELECT 1 FROM clients LIMIT 1").fetchone():
        try:
            with open(LEGACY_CLIENTS_FILE) as f:
                legacy = json.load(f)
            for c in legacy:
                code = new_client_code(c.get("business_name", "client"))
                conn.execute(
                    "INSERT OR IGNORE INTO clients(client_code,business_name,owner_name,"
                    "agent_id,language,voice_id,plan_id,status,ref_code,trial_start,"
                    "trial_end,created_at,config_json) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                    (code, c.get("business_name"), c.get("forward_name") or c.get("owner_name"),
                     c.get("agent_id"), c.get("language", "en"), c.get("voice_id", ""),
                     "trial", "trial", c.get("ref_code", ""), c.get("trial_start"),
                     c.get("trial_end"), c.get("created_at"), json.dumps(c)))
                log_event(conn, code, "migrated", "imported from legacy clients.json")
            conn.commit()
        except Exception:
            pass
    conn.close()


def now_iso():
    return datetime.datetime.now().isoformat(timespec="seconds")


def new_client_code(business_name):
    slug = "".join(ch for ch in business_name.lower().replace(" ", "-")
                   if ch.isalnum() or ch == "-")[:24] or "client"
    return f"{slug}-{secrets.token_hex(2)}"


def log_event(conn, client_code, kind, detail):
    conn.execute("INSERT INTO events(ts,client_code,kind,detail) VALUES(?,?,?,?)",
                 (now_iso(), client_code, kind, detail))


def push_alert(conn, client_code, level, message, dedupe_key=None):
    """Store an alert; send to phone webhook; dedupe repeats within same key."""
    if dedupe_key:
        recent = conn.execute(
            "SELECT 1 FROM alerts WHERE dedupe_key=? AND ts > ?",
            (dedupe_key, (datetime.datetime.now() - datetime.timedelta(days=1)).isoformat())
        ).fetchone()
        if recent:
            return
    conn.execute("INSERT INTO alerts(ts,client_code,level,message,dedupe_key) VALUES(?,?,?,?,?)",
                 (now_iso(), client_code, level, message, dedupe_key))
    if ALERT_WEBHOOK_URL:
        try:
            requests.post(ALERT_WEBHOOK_URL,
                          data=f"[FORGE {level.upper()}] {message}".encode("utf-8"),
                          timeout=10)
        except Exception:
            pass


def propose_action(conn, client_code, action, reason):
    """Queue a consequential action. Executes immediately only if AUTO_EXECUTE=auto."""
    existing = conn.execute(
        "SELECT 1 FROM pending_actions WHERE client_code=? AND action=? AND status='pending'",
        (client_code, action)).fetchone()
    if existing:
        return
    cur = conn.execute(
        "INSERT INTO pending_actions(ts,client_code,action,reason) VALUES(?,?,?,?)",
        (now_iso(), client_code, action, reason))
    log_event(conn, client_code, "action_proposed", f"{action}: {reason}")
    push_alert(conn, client_code, "action",
               f"APPROVAL NEEDED: {action} for {client_code} — {reason}. Open /admin to decide.",
               dedupe_key=f"action:{client_code}:{action}")
    if AUTO_EXECUTE == "auto":
        execute_action(conn, cur.lastrowid)


def execute_action(conn, action_id):
    row = conn.execute("SELECT * FROM pending_actions WHERE id=?", (action_id,)).fetchone()
    if not row or row["status"] not in ("pending", "approved"):
        return False
    ok, note = False, ""
    if row["action"] == "suspend":
        ok, note = set_agent_suspended(conn, row["client_code"], True)
    elif row["action"] == "unsuspend":
        ok, note = set_agent_suspended(conn, row["client_code"], False)
    conn.execute("UPDATE pending_actions SET status=?, decided_at=? WHERE id=?",
                 ("executed" if ok else "failed", now_iso(), action_id))
    log_event(conn, row["client_code"], "action_executed" if ok else "action_failed",
              f"{row['action']} {note}")
    conn.commit()
    return ok


def set_agent_suspended(conn, client_code, suspend):
    """ElevenLabs has no native pause switch, so suspension renames the agent
    with a [SUSPENDED] prefix (visible everywhere, easily reversible) and
    updates our status. If a phone number is attached, unassign it manually
    in the ElevenLabs dashboard — the alert reminds you."""
    c = conn.execute("SELECT * FROM clients WHERE client_code=?", (client_code,)).fetchone()
    if not c or not c["agent_id"]:
        return False, "no agent on record"
    base = f"UD - {c['business_name']}"
    new_name = f"[SUSPENDED] {base}" if suspend else base
    try:
        r = requests.patch(f"{ELEVEN}/v1/convai/agents/{c['agent_id']}",
                           headers={"xi-api-key": ELEVENLABS_API_KEY,
                                    "Content-Type": "application/json"},
                           json={"name": new_name}, timeout=30)
        r.raise_for_status()
    except Exception as e:
        return False, f"rename failed: {e}"
    conn.execute("UPDATE clients SET status=? WHERE client_code=?",
                 ("suspended" if suspend else "active", client_code))
    return True, f"agent renamed to '{new_name}'"


# =========================================================================
# ElevenLabs usage sync
# =========================================================================
def fetch_agent_conversations(agent_id):
    """Pull all conversations for one agent (paginated)."""
    out, cursor = [], None
    for _ in range(50):  # safety bound
        params = {"agent_id": agent_id, "page_size": 100}
        if cursor:
            params["cursor"] = cursor
        r = requests.get(f"{ELEVEN}/v1/convai/conversations",
                         headers={"xi-api-key": ELEVENLABS_API_KEY},
                         params=params, timeout=60)
        r.raise_for_status()
        data = r.json()
        out.extend(data.get("conversations", []))
        cursor = data.get("next_cursor")
        if not cursor or not data.get("has_more", bool(cursor)):
            break
    return out


def extract_credits(convo):
    """Cost fields vary by API version — capture whichever is present."""
    for key in ("call_charge", "cost", "credits", "charge"):
        v = convo.get(key)
        if isinstance(v, (int, float)):
            return float(v)
    meta = convo.get("metadata") or {}
    for key in ("cost", "call_charge", "credits"):
        v = meta.get(key)
        if isinstance(v, (int, float)):
            return float(v)
    return None


def sync_usage():
    """Pull usage for every client agent, attribute it, evaluate thresholds."""
    conn = db()
    summary = {"clients": 0, "new_conversations": 0, "alerts": 0, "errors": []}
    clients = conn.execute(
        "SELECT * FROM clients WHERE agent_id IS NOT NULL AND agent_id != ''").fetchall()

    for c in clients:
        summary["clients"] += 1
        try:
            convos = fetch_agent_conversations(c["agent_id"])
        except Exception as e:
            summary["errors"].append(f"{c['client_code']}: {str(e)[:120]}")
            continue
        for convo in convos:
            cid = convo.get("conversation_id") or convo.get("id")
            if not cid:
                continue
            dur = convo.get("call_duration_secs") or convo.get("duration_secs") or 0
            start = convo.get("start_time_unix_secs") or convo.get("start_unix") or 0
            cur = conn.execute(
                "INSERT OR IGNORE INTO usage(conversation_id,client_code,agent_id,"
                "start_unix,duration_secs,credits,synced_at) VALUES(?,?,?,?,?,?,?)",
                (cid, c["client_code"], c["agent_id"], int(start), float(dur),
                 extract_credits(convo), now_iso()))
            if cur.rowcount:
                summary["new_conversations"] += 1
    conn.commit()

    # ---- per-client thresholds ----
    month_start = datetime.date.today().replace(day=1)
    month_unix = int(time.mktime(month_start.timetuple()))
    for c in clients:
        used = conn.execute(
            "SELECT COALESCE(SUM(duration_secs),0)/60.0 m FROM usage "
            "WHERE client_code=? AND start_unix>=?", (c["client_code"], month_unix)
        ).fetchone()["m"]
        plan = conn.execute("SELECT * FROM plans WHERE id=?", (c["plan_id"],)).fetchone()
        if plan and plan["included_minutes"]:
            pct = used / plan["included_minutes"]
            if pct >= 1.0:
                push_alert(conn, c["client_code"], "critical",
                           f"{c['business_name']} is OVER plan: {used:.0f}/{plan['included_minutes']:.0f} min this month",
                           dedupe_key=f"over:{c['client_code']}:{month_start}")
                if c["status"] != "suspended":
                    propose_action(conn, c["client_code"], "suspend",
                                   f"exceeded included minutes ({used:.0f}/{plan['included_minutes']:.0f})")
                summary["alerts"] += 1
            elif pct >= ALERT_PCT:
                push_alert(conn, c["client_code"], "warning",
                           f"{c['business_name']} at {pct*100:.0f}% of plan ({used:.0f}/{plan['included_minutes']:.0f} min)",
                           dedupe_key=f"warn:{c['client_code']}:{month_start}")
                summary["alerts"] += 1

        # ---- spike detection ----
        now_u = int(time.time())
        last24 = conn.execute(
            "SELECT COALESCE(SUM(duration_secs),0)/60.0 m FROM usage "
            "WHERE client_code=? AND start_unix>=?", (c["client_code"], now_u - 86400)
        ).fetchone()["m"]
        prior14 = conn.execute(
            "SELECT COALESCE(SUM(duration_secs),0)/60.0 m FROM usage "
            "WHERE client_code=? AND start_unix>=? AND start_unix<?",
            (c["client_code"], now_u - 15 * 86400, now_u - 86400)
        ).fetchone()["m"]
        daily_avg = prior14 / 14.0
        if last24 >= SPIKE_MIN_MINUTES and daily_avg > 0 and last24 > SPIKE_MULTIPLIER * daily_avg:
            push_alert(conn, c["client_code"], "warning",
                       f"Usage spike: {c['business_name']} used {last24:.0f} min in 24h "
                       f"(daily average {daily_avg:.1f} min)",
                       dedupe_key=f"spike:{c['client_code']}:{datetime.date.today()}")
            summary["alerts"] += 1

    # ---- account-level ElevenLabs credits ----
    try:
        r = requests.get(f"{ELEVEN}/v1/user/subscription",
                         headers={"xi-api-key": ELEVENLABS_API_KEY}, timeout=30)
        r.raise_for_status()
        sub = r.json()
        used, limit = sub.get("character_count", 0), sub.get("character_limit", 0)
        conn.execute("INSERT OR REPLACE INTO meta VALUES('account_credits',?)",
                     (json.dumps({"used": used, "limit": limit, "at": now_iso()}),))
        if limit and used / limit >= ACCOUNT_ALERT_PCT:
            push_alert(conn, None, "critical",
                       f"ElevenLabs account at {used/limit*100:.0f}% of plan credits ({used:,}/{limit:,})",
                       dedupe_key=f"account:{datetime.date.today().strftime('%Y-%m')}")
            summary["alerts"] += 1
    except Exception as e:
        summary["errors"].append(f"subscription: {str(e)[:120]}")

    conn.execute("INSERT OR REPLACE INTO meta VALUES('last_sync',?)", (now_iso(),))
    conn.commit()
    conn.close()
    return summary


# =========================================================================
# billing
# =========================================================================
def month_bounds(ym=None):
    if ym:
        y, m = int(ym[:4]), int(ym[5:7])
    else:
        t = datetime.date.today()
        y, m = t.year, t.month
    start = datetime.date(y, m, 1)
    end = datetime.date(y + (m == 12), (m % 12) + 1, 1)
    return (int(time.mktime(start.timetuple())), int(time.mktime(end.timetuple())),
            f"{y:04d}-{m:02d}")


def billing_report(ym=None):
    s, e, label = month_bounds(ym)
    conn = db()
    rows = []
    for c in conn.execute("SELECT * FROM clients").fetchall():
        plan = conn.execute("SELECT * FROM plans WHERE id=?", (c["plan_id"],)).fetchone()
        used = conn.execute(
            "SELECT COALESCE(SUM(duration_secs),0)/60.0 m, COUNT(*) n, "
            "COALESCE(SUM(credits),0) cr FROM usage "
            "WHERE client_code=? AND start_unix>=? AND start_unix<?",
            (c["client_code"], s, e)).fetchone()
        base = plan["monthly_base"] if plan else 0
        included = plan["included_minutes"] if plan else 0
        over_rate = plan["overage_per_min"] if plan else 0
        overage_min = max(0.0, used["m"] - included)
        total = base + overage_min * over_rate
        rows.append({
            "client_code": c["client_code"], "business_name": c["business_name"],
            "status": c["status"], "plan": plan["name"] if plan else "?",
            "calls": used["n"], "minutes": round(used["m"], 1),
            "included_minutes": included, "overage_minutes": round(overage_min, 1),
            "base": base, "overage_charge": round(overage_min * over_rate, 2),
            "total_owed": round(total, 2), "credits_consumed": used["cr"],
        })
    conn.close()
    return {"month": label, "clients": rows,
            "grand_total": round(sum(r["total_owed"] for r in rows), 2),
            "total_minutes": round(sum(r["minutes"] for r in rows), 1)}


