# agent creation (v2 features preserved)
# =========================================================================
def generate_agent_prompt(fields):
    if fields["language"] == "bi":
        prompt_language = ("both English and Spanish — greet in English, detect the language "
                           "the caller speaks, and respond in that language for the rest of the call")
        prompt_written_in = "English"
    else:
        prompt_language = "Spanish" if fields["language"] == "es" else "English"
        prompt_written_in = prompt_language
    instructions = f"""You are writing the system prompt for an AI voice agent that answers
phone calls for a small business. The agent's jobs: answer warmly and professionally,
find out why the caller is calling, detect and politely dismiss spam/robocalls/cold sales
pitches, and forward genuine customers or take a detailed message.

Business details:
- Business name: {fields['business_name']}
- What the business does: {fields['description']}
- Business hours: {fields['hours']}
- Forward genuine calls to: {fields['forward_name']}
- Preferred greeting (use it if provided): {fields['greeting'] or 'none provided, write a natural one'}
- Questions the agent should ask callers: {fields['questions'] or 'use sensible defaults for this business type'}
- Things the agent must NEVER say or do: {fields['never_say'] or 'nothing specific'}
- How to handle spam: {fields['spam_policy'] or 'politely end the call and ask to be removed from their list'}
- The agent speaks: {prompt_language}

Write ONLY the system prompt text itself, ready to be given to the voice agent.
Write the entire system prompt in {prompt_written_in}.
It should be thorough but concise, written in second person ("You are...").
Include: the greeting to use, how to identify the caller's purpose, spam detection
behavior, what information to collect from genuine callers, and how to close calls.
"""
    resp = requests.post(
        "https://openrouter.ai/api/v1/chat/completions",
        headers={"Authorization": f"Bearer {OPENROUTER_API_KEY}",
                 "Content-Type": "application/json"},
        json={"model": OPENROUTER_MODEL,
              "messages": [{"role": "user", "content": instructions}]},
        timeout=90)
    resp.raise_for_status()
    return resp.json()["choices"][0]["message"]["content"].strip()


def create_elevenlabs_agent(name, system_prompt, first_message, language,
                            first_message_es=None, voice_id=None):
    tts_model = "eleven_flash_v2_5" if language == "es" else "eleven_flash_v2"
    tts_cfg = {"model_id": tts_model}
    chosen_voice = voice_id or DEFAULT_VOICE_ID
    if chosen_voice:
        tts_cfg["voice_id"] = chosen_voice
    prompt_cfg = {"prompt": system_prompt}
    agent_cfg = {"prompt": prompt_cfg, "first_message": first_message,
                 "language": "en" if language == "bi" else language}
    conversation_config = {"agent": agent_cfg, "tts": tts_cfg}
    if language == "bi":
        prompt_cfg["tools"] = [{"type": "system", "name": "language_detection",
                                "description": ""}]
        es_tts = {"model_id": "eleven_flash_v2_5"}
        if chosen_voice:
            es_tts["voice_id"] = chosen_voice
        conversation_config["language_presets"] = {
            "es": {"overrides": {
                "agent": {"first_message": first_message_es or first_message},
                "tts": es_tts}}}

    def attempt(cfg):
        return requests.post(f"{ELEVEN}/v1/convai/agents/create",
                             headers={"xi-api-key": ELEVENLABS_API_KEY,
                                      "Content-Type": "application/json"},
                             json={"name": name, "conversation_config": cfg},
                             timeout=90)

    resp = attempt(conversation_config)
    if resp.status_code == 400 and language == "bi":
        conversation_config["language_presets"]["es"]["overrides"].pop("tts", None)
        resp = attempt(conversation_config)
    resp.raise_for_status()
    return resp.json().get("agent_id", "unknown")


