def pick_lang(v):
    return "es" if v == "es" else "en"


def pick_agent_lang(v):
    return v if v in ("en", "es", "bi") else "en"


def admin_ok():
    return ADMIN_PASSWORD and request.args.get("key", "") == ADMIN_PASSWORD


# =========================================================================
# routes — intake
# =========================================================================
@app.route("/")
def index():
    lang = pick_lang(request.args.get("lang", "en"))
    conn = db()
    plans = conn.execute("SELECT * FROM plans").fetchall()
    conn.close()
    return render_template_string(FORM_HTML, error=None, logo=LOGO_IMG,
                                  t=T[lang], lang=lang, plans=plans)


@app.route("/create", methods=["POST"])
def create():
    lang = pick_lang(request.form.get("ui_lang", "en"))
    t = T[lang]
    conn = db()
    plans = conn.execute("SELECT * FROM plans").fetchall()

    if request.form.get("password", "") != INTAKE_PASSWORD or not INTAKE_PASSWORD:
        conn.close()
        return render_template_string(FORM_HTML, error=t["wrong_pw"], logo=LOGO_IMG,
                                      t=t, lang=lang, plans=plans), 403

    fields = {k: request.form.get(k, "").strip() for k in
              ("business_name", "description", "hours", "forward_name", "greeting",
               "questions", "never_say", "spam_policy", "ref_code", "voice_id",
               "wa_display_name", "wa_number", "wa_existing")}
    fields["language"] = pick_agent_lang(request.form.get("language", "en"))
    plan_id = request.form.get("plan_id", "trial")
    if plan_id not in [p["id"] for p in plans]:
        plan_id = "trial"

    try:
        system_prompt = generate_agent_prompt(fields)
        greeting_en = f"Hello, you've reached {fields['business_name']}. How can I help you today?"
        greeting_es = f"Hola, se ha comunicado con {fields['business_name']}. ¿En qué puedo ayudarle hoy?"
        greeting_bi = (f"Hello, you've reached {fields['business_name']} — "
                       "si prefiere, puede hablar en español. How can I help you today?")
        es_invite = " Si prefiere, puede hablar en español."
        if fields["greeting"]:
            first_message = fields["greeting"]
            if fields["language"] == "bi" and "español" not in first_message.lower():
                first_message = first_message.rstrip() + es_invite
        elif fields["language"] == "bi":
            first_message = greeting_bi
        elif fields["language"] == "es":
            first_message = greeting_es
        else:
            first_message = greeting_en
        agent_id = create_elevenlabs_agent(
            name=f"UD - {fields['business_name']}",
            system_prompt=system_prompt, first_message=first_message,
            language=fields["language"], first_message_es=greeting_es,
            voice_id=fields["voice_id"])
    except requests.HTTPError as e:
        detail = e.response.text[:600] if e.response is not None else str(e)
        code = e.response.status_code if e.response is not None else "?"
        conn.close()
        return render_template_string(FORM_HTML, error=f"API error ({code}): {detail}",
                                      logo=LOGO_IMG, t=t, lang=lang, plans=plans), 502
    except Exception as e:
        conn.close()
        return render_template_string(FORM_HTML, error=str(e)[:600], logo=LOGO_IMG,
                                      t=t, lang=lang, plans=plans), 500

    today = datetime.date.today()
    client_code = new_client_code(fields["business_name"])
    record = {
        "client_code": client_code, "business_name": fields["business_name"],
        "owner_name": fields["forward_name"], "agent_id": agent_id,
        "language": fields["language"], "voice_id": fields["voice_id"],
        "plan_id": plan_id, "status": "trial", "ref_code": fields["ref_code"],
        "trial_start": today.isoformat(),
        "trial_end": (today + datetime.timedelta(days=TRIAL_DAYS)).isoformat(),
        "created_at": now_iso(),
        "config_json": json.dumps({**fields, "system_prompt": system_prompt,
                                   "first_message": first_message}),
    }
    conn.execute("INSERT INTO clients(client_code,business_name,owner_name,agent_id,"
                 "language,voice_id,plan_id,status,ref_code,trial_start,trial_end,"
                 "created_at,config_json) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)",
                 tuple(record.values()))
    log_event(conn, client_code, "created",
              f"agent {agent_id} · plan {plan_id} · lang {fields['language']}")
    conn.commit()
    conn.close()

    class R(dict):
        __getattr__ = dict.get
    return render_template_string(SUCCESS_HTML, logo=LOGO_IMG, t=t, lang=lang,
                                  c=R(record), trial_days=TRIAL_DAYS)


