@app.route("/tasks/sync")
def tasks_sync():
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    return sync_usage()


@app.route("/admin")
def admin():
    if not admin_ok():
        return "Not authorized. Use /admin?key=YOUR_ADMIN_PASSWORD", 403
    key = request.args.get("key")
    conn = db()
    s, e, _ = month_bounds()
    plans = conn.execute("SELECT * FROM plans").fetchall()
    plan_map = {p["id"]: p for p in plans}
    clients = []
    for c in conn.execute("SELECT * FROM clients ORDER BY created_at DESC").fetchall():
        u = conn.execute("SELECT COALESCE(SUM(duration_secs),0)/60.0 m, COUNT(*) n "
                         "FROM usage WHERE client_code=? AND start_unix>=? AND start_unix<?",
                         (c["client_code"], s, e)).fetchone()
        p = plan_map.get(c["plan_id"])
        included = p["included_minutes"] if p else 0
        over = max(0, u["m"] - included) if p else 0
        est = (p["monthly_base"] + over * p["overage_per_min"]) if p else 0
        clients.append({**dict(c), "mtd_minutes": round(u["m"], 1), "mtd_calls": u["n"],
                        "included": included,
                        "pct": min(130, round(u["m"] / included * 100)) if included else 0,
                        "est_bill": round(est, 2)})
    rep = billing_report()
    acct = json.loads(conn.execute(
        "SELECT value FROM meta WHERE key='account_credits'").fetchone()["value"]) \
        if conn.execute("SELECT 1 FROM meta WHERE key='account_credits'").fetchone() else None
    acct_pct = f"{acct['used']/acct['limit']*100:.0f}%" if acct and acct.get("limit") else "—"
    last_sync = conn.execute("SELECT value FROM meta WHERE key='last_sync'").fetchone()
    pending = conn.execute("SELECT * FROM pending_actions WHERE status='pending' ORDER BY ts DESC").fetchall()
    alerts = conn.execute("SELECT * FROM alerts WHERE acked=0 ORDER BY ts DESC LIMIT 20").fetchall()
    events = conn.execute("SELECT * FROM events ORDER BY id DESC LIMIT 25").fetchall()
    conn.close()
    return render_template_string(
        ADMIN_HTML, key=key, clients=clients, plans=plans,
        month_minutes=rep["total_minutes"], month_total=rep["grand_total"],
        n_clients=len(clients), account_pct=acct_pct,
        last_sync=last_sync["value"] if last_sync else None,
        pending=pending, alerts=alerts, events=events,
        auto_mode="AUTO-EXECUTE" if AUTO_EXECUTE == "auto" else "approval required")


@app.route("/billing")
def billing():
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    return billing_report(request.args.get("month"))


@app.route("/action/<int:action_id>/<decision>", methods=["POST"])
def decide_action(action_id, decision):
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    conn = db()
    if decision == "approve":
        conn.execute("UPDATE pending_actions SET status='approved', decided_at=? WHERE id=?",
                     (now_iso(), action_id))
        conn.commit()
        execute_action(conn, action_id)
    else:
        conn.execute("UPDATE pending_actions SET status='dismissed', decided_at=? WHERE id=?",
                     (now_iso(), action_id))
        row = conn.execute("SELECT client_code FROM pending_actions WHERE id=?", (action_id,)).fetchone()
        log_event(conn, row["client_code"] if row else None, "action_dismissed", f"#{action_id}")
        conn.commit()
    conn.close()
    return redirect(f"/admin?key={request.args.get('key')}")


