@app.route("/export/client/<code>")
def export_client(code):
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    conn = db()
    c = conn.execute("SELECT * FROM clients WHERE client_code=?", (code,)).fetchone()
    if not c:
        return {"error": "not found"}, 404
    usage = [dict(r) for r in conn.execute(
        "SELECT * FROM usage WHERE client_code=? ORDER BY start_unix", (code,))]
    events = [dict(r) for r in conn.execute(
        "SELECT * FROM events WHERE client_code=? ORDER BY id", (code,))]
    conn.close()
    payload = {"client": dict(c), "usage": usage, "audit_trail": events,
               "exported_at": now_iso(),
               "note": "Self-contained record for migrating this client to their own account."}
    return Response(json.dumps(payload, indent=2), mimetype="application/json",
                    headers={"Content-Disposition":
                             f"attachment; filename={code}-export.json"})


@app.route("/backup")
def backup():
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    conn = db()
    dump = {}
    for tbl in ("plans", "clients", "usage", "events", "alerts", "pending_actions", "meta"):
        dump[tbl] = [dict(r) for r in conn.execute(f"SELECT * FROM {tbl}")]
    conn.close()
    return Response(json.dumps(dump, indent=2), mimetype="application/json",
                    headers={"Content-Disposition":
                             "attachment; filename=forge-backup.json"})


@app.route("/restore", methods=["POST"])
def restore():
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    try:
        dump = request.get_json(force=True)
    except Exception:
        return {"error": "POST the backup JSON as the request body"}, 400
    conn = db()
    counts = {}
    for tbl in ("plans", "clients", "usage", "events", "alerts", "pending_actions", "meta"):
        rows = dump.get(tbl, [])
        for r in rows:
            cols = ",".join(r.keys())
            qs = ",".join("?" * len(r))
            conn.execute(f"INSERT OR REPLACE INTO {tbl}({cols}) VALUES({qs})",
                         tuple(r.values()))
        counts[tbl] = len(rows)
    conn.commit()
    conn.close()
    return {"restored": counts}


@app.route("/affiliates")
def affiliates():
    """Commission report: AFF_COMMISSION_PCT% of monthly base for referred clients,
    for their first AFF_WINDOW_MONTHS months. Adjust via env vars."""
    if not admin_ok():
        return {"error": "unauthorized"}, 403
    conn = db()
    plans = {p["id"]: p for p in conn.execute("SELECT * FROM plans")}
    today = datetime.date.today()
    book = {}
    for c in conn.execute("SELECT * FROM clients WHERE ref_code != '' AND ref_code IS NOT NULL"):
        try:
            start = datetime.date.fromisoformat(c["trial_start"])
        except Exception:
            continue
        months_in = (today.year - start.year) * 12 + (today.month - start.month)
        in_window = 0 <= months_in < AFF_WINDOW_MONTHS
        base = plans[c["plan_id"]]["monthly_base"] if c["plan_id"] in plans else 0
        active = c["status"] in ("active", "trial") and in_window
        entry = book.setdefault(c["ref_code"], {"clients": [], "monthly_commission": 0.0})
        entry["clients"].append({
            "business": c["business_name"], "plan": c["plan_id"], "status": c["status"],
            "referred_on": c["trial_start"], "months_elapsed": months_in,
            "in_commission_window": in_window,
            "commission_this_month": round(base * AFF_COMMISSION_PCT / 100, 2) if active else 0,
        })
        if active:
            entry["monthly_commission"] += base * AFF_COMMISSION_PCT / 100
    for v in book.values():
        v["monthly_commission"] = round(v["monthly_commission"], 2)
    conn.close()
    return {"commission_pct": AFF_COMMISSION_PCT, "window_months": AFF_WINDOW_MONTHS,
            "note": "Adjust via AFF_COMMISSION_PCT and AFF_WINDOW_MONTHS env vars on Render.",
            "affiliates": book,
            "total_owed_this_month": round(sum(v["monthly_commission"] for v in book.values()), 2)}


